snippets.D0010:
// D0010 · Upsert (Intermedio, Base de datos)
// PowerBuilder 2025 / PowerScript - Dynamic SQL
string ls_sql
ls_sql = "MERGE dbo.users AS t
USING (SELECT N'Ana' AS name, N'ana@demo.cl' AS email) AS s
ON t.email = s.email
WHEN MATCHED THEN UPDATE SET t.name = s.name
WHEN NOT MATCHED THEN INSERT(name,email) VALUES(s.name,s.email);"
EXECUTE IMMEDIATE :ls_sql USING SQLCA;
IF SQLCA.SQLCode <> 0 THEN
  // manejar error: SQLCA.SQLErrText
END IF

